DO $$
DECLARE
  d   jsonb := $jdata$[{"slug":"serve-rs2","name":"Serve Robotics RS2","manufacturer":"Serve Robotics","type":"delivery_ground","introduced_year":2023,"specs_json":{"weight_kg":22,"payload_kg":15,"max_speed_kmh":10,"battery_wh":1500,"range_km":40,"drive":"4-wheel differential","ip_rating":"IP65","cameras":6,"lidar":true},"notes":"Sidewalk delivery robot operating in Los Angeles and other US cities. Partnerships with Uber Eats and 7-Eleven.","failure_modes":[{"component":"drive wheel hub motor bearing","symptom":"audible grinding from drivetrain, vibration spike at low speed, increased motor current draw by 15-25% above baseline","root_cause":"bearing race spalling from water ingress via inadequate IP sealing after repeated curb impact events; grit contamination accelerates race wear","severity":"high","mtbf_hours":800,"source_urls":["unverified-training-data"],"confidence":"medium","tags":["drivetrain","bearing","mechanical","water-ingress","curb-impact"],"repair_protocol":{"title":"Drive Hub Motor Bearing Replacement","steps":[{"step":1,"action":"Power down robot via fleet management console; engage software lockout; verify zero-energy state on dash LED","tool":null,"warning":"Capacitor discharge \u2014 wait 2 minutes after power-off before touching drive electronics"},{"step":2,"action":"Remove 6x M5 wheel mounting bolts; extract full wheel/hub assembly from chassis dropouts","tool":"4mm hex key, wheel puller","warning":null},{"step":3,"action":"Remove hub motor end cap retaining snap ring; carefully extract rotor from stator housing; label motor phase wires","tool":"snap ring pliers, heat gun at 60\u00b0C to soften thread-lock","warning":"Do not stress motor phase wires \u2014 they are short-bonded to stator windings"},{"step":4,"action":"Press out degraded bearing from rotor carrier using bearing press; inspect stator for corrosion deposits or winding discoloration","tool":"hydraulic bearing press, inspection light, magnifying glass","warning":null},{"step":5,"action":"Clean bore with isopropyl alcohol; apply 2-3 drops Loctite 648 retaining compound; press new NTN 6203-2RS sealed bearing to full seat depth","tool":"bearing press, Loctite 648","warning":"Do not spin bearing until adhesive cures 30 minutes at 22\u00b0C"},{"step":6,"action":"Inspect and replace IP65 end cap gasket; apply thin bead of Dow Corning 732 RTV to mating face; reassemble rotor; torque end cap bolts to 12 Nm","tool":"torque wrench 0-25 Nm, Dow Corning 732 RTV sealant","warning":null},{"step":7,"action":"Reinstall wheel assembly; hand-tighten then torque M5 bolts to 8 Nm in star pattern","tool":"torque wrench","warning":null},{"step":8,"action":"Remove software lockout; run 10-minute drive cycle on flat surface; verify current draw <\u00b110% of factory baseline; confirm vibration RMS <0.4g on IMU","tool":"fleet management console, multimeter","warning":null}],"tools_required":["4mm hex key","snap ring pliers","hydraulic bearing press","heat gun","torque wrench 0-25 Nm","multimeter","isopropyl alcohol"],"parts":[{"part_name":"NTN 6203-2RS Sealed Deep-Groove Bearing","part_number":"6203LLBC3/2AS","supplier":"NTN Bearing Corporation of America","unit_cost_usd":9,"qty":2},{"part_name":"Dow Corning 732 RTV Multi-Purpose Sealant 90g","part_number":"DC-732-90G","supplier":"Dow Corning / Dupont","unit_cost_usd":18,"qty":1},{"part_name":"Loctite 648 Retaining Compound 50ml","part_number":"1835100","supplier":"Henkel / Loctite","unit_cost_usd":24,"qty":1},{"part_name":"Hub Motor End Cap IP65 Gasket Kit","part_number":"SRV-RS2-GASKET-001","supplier":"Serve Robotics Service Parts","unit_cost_usd":12,"qty":1}],"labor_minutes":65,"skill_level":"intermediate","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"motor_current_draw_pct_baseline","signal_source":"motor controller CAN bus","threshold_value":115,"threshold_operator":">","threshold_unit":"percent","lead_time_hours":24,"confidence":0.72},{"signal_name":"drivetrain_vibration_rms","signal_source":"onboard IMU","threshold_value":0.8,"threshold_operator":">","threshold_unit":"g","lead_time_hours":8,"confidence":0.8},{"signal_name":"wheel_motor_temperature_delta","signal_source":"NTC thermistor on motor controller","threshold_value":15,"threshold_operator":">","threshold_unit":"celsius_delta_from_ambient","lead_time_hours":12,"confidence":0.65}]},{"component":"360\u00b0 lidar sensor (Velodyne/Ouster derivative)","symptom":"point cloud density drops >30%, phantom obstacle detections in clear path, robot stops unexpectedly or navigates erratically","root_cause":"lens window contamination from road grime, rain, and exhaust particulates; secondary failure mode is bearing wear in rotating scanner head after continuous 24/7 operation","severity":"high","mtbf_hours":5000,"source_urls":["unverified-training-data"],"confidence":"medium","tags":["sensor","lidar","navigation","contamination","perception"],"repair_protocol":{"title":"Lidar Lens Cleaning and Scanner Health Check","steps":[{"step":1,"action":"Park robot in safe off-street location; engage lockout via fleet console","tool":null,"warning":null},{"step":2,"action":"Remove lidar protective dome (4x M3 captive screws, quarter-turn); expose lens window","tool":"Torx T10 driver","warning":"Do not touch lens glass \u2014 handle dome by edge only"},{"step":3,"action":"Apply 2 sprays of Optically Clear Lens Cleaning Solution to lint-free microfibre cloth; wipe lens in single radial strokes from center outward; repeat until surface is haze-free","tool":"microfibre cloth, Zeiss Lens Care spray","warning":"Never use paper towels or circular wiping \u2014 scratches anti-reflection coating"},{"step":4,"action":"Inspect rotating head: spin by hand with power off; confirm smooth rotation, no grinding or notchiness; check motor flex cable for fraying","tool":"inspection light","warning":null},{"step":5,"action":"Reinstall dome; power on; run diagnostic scan tool to measure point cloud return rate \u2014 must be >92% of factory baseline","tool":"fleet diagnostic console","warning":null},{"step":6,"action":"If point cloud recovery <92% after cleaning, replace full lidar module per manufacturer RMA procedure","tool":null,"warning":"Full module replacement requires re-calibration of sensor-to-chassis transform \u2014 do not skip calibration step"}],"tools_required":["Torx T10 driver","microfibre cloths","Zeiss Lens Care spray","fleet diagnostic console"],"parts":[{"part_name":"Zeiss Lens Care Plus Spray 240ml","part_number":"000000-2096-075","supplier":"Carl Zeiss Vision","unit_cost_usd":14,"qty":1},{"part_name":"Lidar Protective Dome Replacement","part_number":"SRV-RS2-LIDAR-DOME","supplier":"Serve Robotics Service Parts","unit_cost_usd":45,"qty":1}],"labor_minutes":20,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"lidar_return_rate_pct","signal_source":"navigation stack / lidar driver","threshold_value":88,"threshold_operator":"<","threshold_unit":"percent","lead_time_hours":48,"confidence":0.85},{"signal_name":"obstacle_false_positive_rate_per_km","signal_source":"navigation software log","threshold_value":5,"threshold_operator":">","threshold_unit":"count_per_km","lead_time_hours":12,"confidence":0.74}]},{"component":"main traction battery (Li-ion pack)","symptom":"reduced range >20% below spec, battery thermal event warning, cells failing to balance above 90% SOC","root_cause":"cell imbalance from repeated partial-charge cycles and thermal cycling in ambient temperatures <5\u00b0C or >40\u00b0C; accelerated by vibration-induced micro-shorts in 18650/21700 cell holders","severity":"high","mtbf_hours":2000,"source_urls":["unverified-training-data"],"confidence":"medium","tags":["battery","BMS","thermal","range","cell-imbalance"],"repair_protocol":{"title":"Battery Pack Cell Balance Inspection and BMS Reset","steps":[{"step":1,"action":"Park robot; connect to fleet console; pull BMS telemetry report \u2014 identify cells with voltage delta >50mV from pack median","tool":"fleet console / BMS diagnostic port","warning":null},{"step":2,"action":"Perform forced balance charge: set BMS to slow-charge mode (0.2C); allow 8-hour passive balancing cycle","tool":"fleet console BMS balance command","warning":null},{"step":3,"action":"If delta persists >80mV post-balance, remove battery pack (4x M6 bolts, 2 Anderson connector locks)","tool":"5mm hex key, Anderson connector tool","warning":"Wear insulated gloves; pack voltage is 48V nominal \u2014 arc flash risk"},{"step":4,"action":"Transfer pack to bench; connect to Texas Instruments BQ78350 BMS evaluation board; run full cell individual voltage sweep; flag cells <3.0V or >4.22V","tool":"TI BQ78350 evaluation kit, DMM with cell-probe adapter","warning":null},{"step":5,"action":"Replace degraded cell modules (hot-swap modules if pack design permits); update BMS firmware to latest release via SPI flash tool","tool":"SPI flash programmer, soldering station","warning":"Cell replacement in Li-ion packs is advanced \u2014 refer to certified battery technician if >3 cells flagged"},{"step":6,"action":"Reinstall pack; run 3-cycle capacity test (full charge/discharge); confirm capacity >85% of nameplate; log result in fleet system","tool":"fleet console","warning":null}],"tools_required":["fleet console","5mm hex key","Anderson connector tool","insulated gloves","DMM","TI BQ78350 evaluation kit"],"parts":[{"part_name":"Texas Instruments BQ78350 BMS Replacement IC","part_number":"BQ78350DRBT","supplier":"Texas Instruments / Mouser Electronics","unit_cost_usd":8,"qty":1},{"part_name":"21700 Li-ion Cell 5000mAh (replacement)","part_number":"INR21700-50E","supplier":"Samsung SDI / Liion Wholesale","unit_cost_usd":7,"qty":4}],"labor_minutes":120,"skill_level":"advanced","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"bms_cell_voltage_delta_mv","signal_source":"BMS CAN telemetry","threshold_value":80,"threshold_operator":">","threshold_unit":"millivolts","lead_time_hours":72,"confidence":0.82},{"signal_name":"pack_capacity_pct_nameplate","signal_source":"BMS state-of-health register","threshold_value":80,"threshold_operator":"<","threshold_unit":"percent","lead_time_hours":168,"confidence":0.88},{"signal_name":"battery_temperature_max_celsius","signal_source":"BMS NTC array","threshold_value":45,"threshold_operator":">","threshold_unit":"celsius","lead_time_hours":2,"confidence":0.91}]},{"component":"camera array (front/side/rear 1080p cameras)","symptom":"lens condensation causing blurred perception output, camera frames reported as 'low confidence' by vision stack, increased pedestrian detection latency","root_cause":"thermal differential between cold ambient and warm robot body causes moisture condensation on exterior lens surfaces; hydrophobic coating degradation after 6-12 months outdoor exposure","severity":"medium","mtbf_hours":4000,"source_urls":["unverified-training-data"],"confidence":"medium","tags":["sensor","camera","vision","condensation","perception","weather"],"repair_protocol":{"title":"Camera Lens Defogging and Hydrophobic Recoat","steps":[{"step":1,"action":"Identify affected cameras from fleet diagnostic image quality scores; flag cameras with mean SSIM <0.75 versus clear reference","tool":"fleet console image quality dashboard","warning":null},{"step":2,"action":"Power down affected camera module; remove housing cover (3x M2.5 screws)","tool":"JIS #0 screwdriver","warning":"Fragile ribbon cable at camera module \u2014 do not stress"},{"step":3,"action":"Apply Rain-X Original Glass Treatment to exterior lens surface with cotton applicator; buff to clear with microfibre cloth; allow 5 minutes cure","tool":"Rain-X Original, cotton applicator, microfibre cloth","warning":"Keep Rain-X away from rubber gaskets \u2014 causes swelling"},{"step":4,"action":"Inspect IP gasket around lens housing; replace if any cracking or compression set visible; apply thin bead of Dow Corning 732 to seal","tool":"Dow Corning 732, gasket pick tool","warning":null},{"step":5,"action":"Reassemble housing; power on; run image quality check \u2014 confirm SSIM >0.9 and vision stack confidence >0.85","tool":"fleet diagnostic console","warning":null}],"tools_required":["JIS #0 screwdriver","microfibre cloths","Rain-X Original","Dow Corning 732"],"parts":[{"part_name":"Rain-X Original Glass Water Repellent 103ml","part_number":"800001771","supplier":"Rain-X / ITW Global Brands","unit_cost_usd":8,"qty":1},{"part_name":"Camera Module IP Gasket Set","part_number":"SRV-RS2-CAM-GSKT","supplier":"Serve Robotics Service Parts","unit_cost_usd":15,"qty":1}],"labor_minutes":25,"skill_level":"basic","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"camera_image_quality_ssim","signal_source":"vision processing node","threshold_value":0.75,"threshold_operator":"<","threshold_unit":"ssim_score","lead_time_hours":4,"confidence":0.78},{"signal_name":"ambient_humidity_pct","signal_source":"environmental sensor","threshold_value":85,"threshold_operator":">","threshold_unit":"percent_rh","lead_time_hours":1,"confidence":0.6}]},{"component":"LTE/5G cellular modem (IoT connectivity module)","symptom":"robot stops mid-delivery and enters safe-stop mode, fleet console shows 'connection lost', delayed return-to-home behavior","root_cause":"cellular modem firmware crash triggered by malformed network registration packets from carrier edge nodes; secondary cause is antenna connector corrosion from humidity ingress loosening SMA connector impedance match","severity":"medium","mtbf_hours":3500,"source_urls":["unverified-training-data"],"confidence":"low","tags":["connectivity","IoT","cellular","firmware","antenna"],"repair_protocol":{"title":"Cellular Modem Firmware Update and Antenna Inspection","steps":[{"step":1,"action":"Connect to robot via local WiFi or physical Ethernet port (maintenance port under belly panel)","tool":"Ethernet cable, laptop","warning":null},{"step":2,"action":"SSH into robot OS; check modem status: `mmcli -m 0 --status`; confirm if modem shows 'failed' or 'searching' state","tool":"SSH terminal","warning":null},{"step":3,"action":"Attempt modem soft reset: `mmcli -m 0 --reset`; wait 60 seconds; re-check status","tool":"SSH terminal","warning":null},{"step":4,"action":"If persistent, flash latest modem firmware via fleet OTA command or USB tether: `fwupd upgrade --modem`","tool":"SSH terminal or USB tether","warning":"Do not interrupt power during firmware flash \u2014 will brick modem"},{"step":5,"action":"Inspect SMA antenna connectors (2x on modem module): check torque at 0.5 Nm; clean contacts with DeoxIT D5; re-seat connectors","tool":"SMA torque wrench 0.5Nm, DeoxIT D5 spray","warning":null},{"step":6,"action":"Run 30-minute connectivity soak test via fleet console; confirm 0 disconnections and latency <200ms","tool":"fleet console","warning":null}],"tools_required":["Ethernet cable","laptop with SSH","SMA torque wrench 0.5Nm","DeoxIT D5"],"parts":[{"part_name":"DeoxIT D5 Contact Cleaner 5% 142g","part_number":"D5S-6","supplier":"Caig Laboratories","unit_cost_usd":16,"qty":1},{"part_name":"SMA Female Connector IP67 Panel Mount (replacement)","part_number":"5-1814832-1","supplier":"TE Connectivity / Mouser","unit_cost_usd":4,"qty":2}],"labor_minutes":35,"skill_level":"intermediate","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"cellular_rssi_dbm","signal_source":"modem AT command interface","threshold_value":-100,"threshold_operator":"<","threshold_unit":"dBm","lead_time_hours":2,"confidence":0.7},{"signal_name":"modem_reconnect_count_per_hour","signal_source":"fleet telemetry daemon","threshold_value":3,"threshold_operator":">","threshold_unit":"count_per_hour","lead_time_hours":6,"confidence":0.75}]},{"component":"chassis frame / body panel (structural)","symptom":"visible cracking at wheel arch gussets, frame flex under payload, audible creak over bumps","root_cause":"repeated curb drop impacts (5-15mm height) exceeding design fatigue load at chassis tube weld joints; aluminum alloy 6061-T6 weld heat-affected zone embrittlement","severity":"high","mtbf_hours":1200,"source_urls":["unverified-training-data"],"confidence":"low","tags":["structural","chassis","fatigue","curb-impact","frame"],"repair_protocol":{"title":"Chassis Crack Inspection and Gusset Plate Reinforcement","steps":[{"step":1,"action":"Remove all body panels; perform full visual inspection of chassis tube welds with 10x magnification loupe; mark any cracks with paint pen","tool":"10x magnification loupe, paint pen, inspection light","warning":null},{"step":2,"action":"Photograph all crack locations for engineering review before any repair; submit to fleet engineering Slack channel","tool":"camera or phone","warning":"Do not operate robot with confirmed chassis crack \u2014 retire from service immediately"},{"step":3,"action":"If crack is <10mm at non-load-bearing panel: clean area with acetone; apply JB Weld Aluminum Epoxy across crack; clamp and cure 24h","tool":"acetone, JB Weld Aluminum Epoxy, clamps","warning":"JB Weld structural repair is field-expedient only \u2014 engineering sign-off required before return to service"},{"step":4,"action":"For weld joint cracks: robot must be returned to depot; certified welder performs TIG re-weld and 2mm aluminum gusset plate bonding with Scotch-Weld 2216","tool":"TIG welder, 3M Scotch-Weld 2216 B/A","warning":"Field welding of 6061-T6 is not recommended without post-weld heat treatment \u2014 depot repair only"},{"step":5,"action":"Post-repair load test: apply full 15kg payload; drive over standard curb-drop test (80mm) 10 times; re-inspect all welds","tool":"15kg test payload, standard curb fixture","warning":null}],"tools_required":["10x magnifying loupe","paint pen","camera","acetone","JB Weld Aluminum Epoxy","clamps"],"parts":[{"part_name":"JB Weld 8267 Aluminum Epoxy 28g","part_number":"8267","supplier":"JB Weld / Ace Hardware","unit_cost_usd":9,"qty":1},{"part_name":"3M Scotch-Weld 2216 B/A Epoxy 200ml","part_number":"62-3280-0076-8","supplier":"3M Industrial","unit_cost_usd":55,"qty":1}],"labor_minutes":90,"skill_level":"advanced","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"chassis_vibration_asymmetry_ratio","signal_source":"IMU left vs right accelerometer delta","threshold_value":1.3,"threshold_operator":">","threshold_unit":"ratio","lead_time_hours":48,"confidence":0.55},{"signal_name":"cumulative_curb_drop_events","signal_source":"IMU shock event counter in fleet log","threshold_value":500,"threshold_operator":">","threshold_unit":"count","lead_time_hours":240,"confidence":0.62}]},{"component":"motor controller (BLDC FOC controller)","symptom":"thermal throttling warning in fleet console, motor speed limited to 50% of commanded value, controller reboots mid-run","root_cause":"controller MOSFET junction overheating due to clogged thermal pad contact between MOSFET and heatsink, compounded by increased bearing drag increasing motor load; thermal runaway risk above 85\u00b0C junction temp","severity":"high","mtbf_hours":3000,"source_urls":["unverified-training-data"],"confidence":"medium","tags":["motor-controller","thermal","BLDC","MOSFET","drivetrain"],"repair_protocol":{"title":"Motor Controller Thermal Interface Replacement","steps":[{"step":1,"action":"Power down robot; wait 5 minutes for controller thermal soak before opening enclosure","tool":null,"warning":"Controller heatsink may be at 70\u00b0C+ immediately after shutdown \u2014 burn hazard"},{"step":2,"action":"Remove controller enclosure cover (6x M3 screws); photograph thermal pad condition and PCB state","tool":"JIS #1 screwdriver, camera","warning":null},{"step":3,"action":"Remove 4x M3 heatsink mounting screws; separate heatsink from PCB; note old thermal pad condition (compression, dry-out, cracking)","tool":"JIS #1 screwdriver, plastic pry tool","warning":null},{"step":4,"action":"Clean both mating surfaces with isopropyl alcohol; allow to dry fully","tool":"isopropyl alcohol 99%, lint-free cloth","warning":null},{"step":5,"action":"Apply new Fujipoly XR-m or Bergquist GP3000S30 thermal pad (3mm thick, cut to MOSFET cluster footprint); remove protective liners; seat heatsink; torque M3 screws to 0.8 Nm","tool":"torque screwdriver, scissors","warning":null},{"step":6,"action":"Reassemble enclosure; power on; run motor at 100% load for 10 minutes; verify controller temperature plateau <70\u00b0C via fleet telemetry","tool":"fleet console","warning":null}],"tools_required":["JIS #1 screwdriver","plastic pry tool","isopropyl alcohol 99%","lint-free cloth","torque screwdriver 0-1Nm","scissors"],"parts":[{"part_name":"Bergquist GP3000S30 Thermal Pad 3mm 100x100mm","part_number":"GP3000S30-0.030-00-161","supplier":"Henkel Bergquist / Digi-Key","unit_cost_usd":22,"qty":1},{"part_name":"Thermal Interface Screw Kit M3x8 SS","part_number":"KIT-M3-TIM-8","supplier":"McMaster-Carr","unit_cost_usd":5,"qty":1}],"labor_minutes":40,"skill_level":"intermediate","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"motor_controller_junction_temp_celsius","signal_source":"motor controller NTC / CAN telemetry","threshold_value":78,"threshold_operator":">","threshold_unit":"celsius","lead_time_hours":4,"confidence":0.88},{"signal_name":"thermal_throttle_events_per_hour","signal_source":"motor controller fault register","threshold_value":2,"threshold_operator":">","threshold_unit":"count_per_hour","lead_time_hours":8,"confidence":0.83}]}],"suppliers":[{"name":"NTN Bearing Corporation of America","website":"https://www.ntnamericas.com","region":"NA","component_types":["bearing","seal"],"lead_time_days":5,"risk_level":"low"},{"name":"SKF Bearing Americas","website":"https://www.skf.com","region":"NA","component_types":["bearing","seal"],"lead_time_days":5,"risk_level":"low"},{"name":"Texas Instruments","website":"https://www.ti.com","region":"NA","component_types":["BMS IC","motor controller IC"],"lead_time_days":14,"risk_level":"medium"},{"name":"Henkel Bergquist","website":"https://www.henkel-adhesives.com","region":"NA","component_types":["thermal interface material"],"lead_time_days":7,"risk_level":"low"},{"name":"Serve Robotics Service Parts","website":"https://www.serverobotics.com","region":"NA","component_types":["chassis","body panel","gasket","sensor housing"],"lead_time_days":10,"risk_level":"medium"}],"research_sources":["unverified-training-data"]},{"slug":"figure-02","name":"Figure 02","manufacturer":"Figure AI","type":"humanoid","introduced_year":2024,"specs_json":{"weight_kg":70,"dof":44,"height_m":1.7,"payload_kg":20,"runtime_h":5,"hand_dof":16,"walking_speed_ms":1.2,"battery_wh":2200},"notes":"Commercial humanoid with OpenAI VLA integration. BMW manufacturing deployment. Documentation is sparse \u2014 failure modes based on generic humanoid engineering principles. Confidence: low.","failure_modes":[{"component":"leg actuator (knee / hip joint \u2014 harmonic drive + BLDC)","symptom":"joint position error alarms, gait asymmetry detected by IMU, joint makes clicking sound during stance phase, reduced torque output in affected limb","root_cause":"harmonic drive flex spline fatigue cracking from repetitive high-torque stance loading; wave generator bearing wear increasing backlash beyond firmware compensation range; motor winding thermal stress from sustained walking duty cycle","severity":"critical","mtbf_hours":3000,"source_urls":["unverified-training-data"],"confidence":"low","tags":["actuator","harmonic-drive","humanoid","leg","joint","critical"],"repair_protocol":{"title":"Leg Actuator Joint Inspection and Harmonic Drive Assessment","steps":[{"step":1,"action":"Command robot to maintenance pose via control interface (lying flat, all joints to home position); engage full software E-stop and lockout","tool":"robot control terminal","warning":"Humanoid joints store significant energy in springs/actuators \u2014 never manually move limbs without confirming software lockout"},{"step":2,"action":"Measure joint backlash with dial indicator on output link: apply \u00b15 Nm hand torque; read dial indicator deflection at 200mm moment arm \u2014 backlash >0.3mm indicates harmonic drive wear","tool":"dial indicator, 200mm moment arm fixture, force gauge","warning":null},{"step":3,"action":"Pull joint torque telemetry from last 7 days: plot torque vs position \u2014 increasing torque-to-position ratio (stiffness increase) or torque ripple >15% indicates flex spline damage","tool":"robot diagnostic software","warning":null},{"step":4,"action":"If backlash >0.3mm or torque ripple >15%: remove actuator module (typically 6-8 M5 bolts per actuator, 2 motor connectors); send to manufacturer for harmonic drive replacement \u2014 not field-repairable","tool":"M5 hex key set, torque wrench, connector extraction tool","warning":"Harmonic drive replacement requires precision assembly tooling and calibration \u2014 depot/manufacturer service only"},{"step":5,"action":"After actuator reinstallation: run full joint calibration routine from robot software; verify joint position accuracy <0.1\u00b0 across full range of motion","tool":"robot calibration software","warning":null}],"tools_required":["robot control terminal","dial indicator","moment arm fixture","force gauge","M5 hex key set","torque wrench"],"parts":[{"part_name":"Harmonic Drive Component Set (wave generator + flex spline + circular spline)","part_number":"CSF-20-100-2A-GR","supplier":"Harmonic Drive Systems (Harmonic Drive LLC)","unit_cost_usd":1800,"qty":1},{"part_name":"BLDC Actuator Replacement Module (Figure AI OEM)","part_number":"FIG02-ACT-LEG-MOD","supplier":"Figure AI Service","unit_cost_usd":4500,"qty":1}],"labor_minutes":180,"skill_level":"specialist","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"joint_backlash_mm_at_200mm_arm","signal_source":"actuator encoder + torque sensor cross-check","threshold_value":0.25,"threshold_operator":">","threshold_unit":"mm","lead_time_hours":168,"confidence":0.65},{"signal_name":"joint_torque_ripple_pct","signal_source":"joint torque sensor CAN telemetry","threshold_value":12,"threshold_operator":">","threshold_unit":"percent","lead_time_hours":48,"confidence":0.61},{"signal_name":"gait_asymmetry_score","signal_source":"IMU gait analysis module","threshold_value":0.15,"threshold_operator":">","threshold_unit":"symmetry_index_deviation","lead_time_hours":24,"confidence":0.7}]},{"component":"sensor fusion system (proprioception + exteroception)","symptom":"robot stumbles on uneven terrain it previously handled, balance controller intervention rate increases, 'sensor fusion degraded' warning in logs","root_cause":"IMU calibration drift from thermal cycling and vibration causing accelerometer bias error accumulation; camera-to-IMU extrinsic calibration drift from vibration loosening camera mount; temporal synchronization error between sensor streams (>5ms) causing state estimation noise","severity":"high","mtbf_hours":2000,"source_urls":["unverified-training-data"],"confidence":"low","tags":["sensor","IMU","sensor-fusion","calibration","humanoid","balance"],"repair_protocol":{"title":"IMU Calibration Reset and Camera Extrinsic Recalibration","steps":[{"step":1,"action":"Place robot on precision flat surface (\u00b10.1\u00b0 level); run IMU static calibration routine from control software: robot must be stationary for 5 minutes; software estimates gyro bias and accelerometer offset","tool":"precision level \u00b10.1\u00b0, robot calibration software","warning":"Robot must be on vibration-isolated surface for calibration \u2014 do not run on concrete near forklifts or HVAC equipment"},{"step":2,"action":"After IMU calibration, run camera-IMU temporal synchronization check: wave calibration target in front of cameras; software estimates time offset between camera frames and IMU samples \u2014 must be <2ms","tool":"AprilTag calibration target, robot calibration software","warning":null},{"step":3,"action":"Run camera extrinsic calibration: mount multi-tag calibration board at known distance; drive robot through slow head movements; software updates camera-to-IMU rigid body transform","tool":"multi-tag calibration board (0.5m x 0.5m), robot software","warning":null},{"step":4,"action":"Verify calibration: run robot on standard test course (flat, 10cm step, 5\u00b0 ramp, 180\u00b0 turn); balance intervention rate should be <5 per minute","tool":"standard test course, robot telemetry logger","warning":null},{"step":5,"action":"If calibration does not converge (residual error >0.5\u00b0): inspect camera mount bolts for looseness (M2.5 or M3); retorque; repeat calibration","tool":"M2.5/M3 hex key, torque screwdriver","warning":null}],"tools_required":["precision level \u00b10.1\u00b0","AprilTag calibration target","multi-tag calibration board","robot calibration software","M2.5/M3 hex key"],"parts":[{"part_name":"AprilTag Multi-Tag Calibration Board A2 size","part_number":"APTAG-CALIB-A2","supplier":"AprilRobotics / Amazon","unit_cost_usd":35,"qty":1}],"labor_minutes":90,"skill_level":"advanced","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"imu_gyro_bias_deg_per_s","signal_source":"IMU internal bias register","threshold_value":0.05,"threshold_operator":">","threshold_unit":"degrees_per_second","lead_time_hours":72,"confidence":0.62},{"signal_name":"balance_controller_intervention_rate_per_min","signal_source":"balance controller telemetry","threshold_value":8,"threshold_operator":">","threshold_unit":"count_per_minute","lead_time_hours":12,"confidence":0.68}]},{"component":"battery thermal management system","symptom":"battery temperature warning above 40\u00b0C during operation, charging stops at 80% SOC as thermal protection engages, reduced runtime from 5h to 3h","root_cause":"cooling loop pump flow reduction from air bubble accumulation in liquid cooling circuit; thermal interface pad dry-out between battery cells and cooling plate after 18 months; cell chemistry sensitivity to BMW factory floor ambient temperature (28-35\u00b0C)","severity":"high","mtbf_hours":4000,"source_urls":["unverified-training-data"],"confidence":"low","tags":["battery","thermal","cooling","humanoid","BMS"],"repair_protocol":{"title":"Battery Cooling Circuit Bleed and Thermal Pad Inspection","steps":[{"step":1,"action":"Pull battery thermal telemetry for past 14 days: plot peak cell temperature vs ambient; if delta >12\u00b0C at rest, suspect cooling degradation","tool":"robot diagnostic dashboard","warning":null},{"step":2,"action":"Access battery cooling loop service port (location varies \u2014 refer to Figure AI service bulletin); attach cooling system pressure gauge; measure static pressure \u2014 must hold 0.8 bar over 10 minutes (no drop = no leak)","tool":"cooling system pressure gauge, Figure AI service docs","warning":null},{"step":3,"action":"Bleed cooling loop: open bleed nipple at highest point in loop; run pump at low speed; wait for continuous coolant flow without bubbles from bleed nipple; close nipple","tool":"bleed nipple tool, catch container","warning":null},{"step":4,"action":"If temperature delta persists after bleed: access battery cooling plate (specialist-level disassembly); replace Bergquist GP2000 thermal pads between cells and cooling plate","tool":"Bergquist GP2000 thermal pad, precision knife, isopropyl alcohol","warning":"Battery disassembly at this level is manufacturer service only \u2014 high voltage exposure"},{"step":5,"action":"After service: run full charge/discharge cycle in 25\u00b0C ambient; confirm peak cell temp <38\u00b0C throughout","tool":"robot diagnostic dashboard, ambient thermometer","warning":null}],"tools_required":["robot diagnostic dashboard","cooling pressure gauge","bleed nipple tool","ambient thermometer"],"parts":[{"part_name":"Bergquist GP2000 Thermal Pad 1mm 150x150mm","part_number":"GP2000-0.010-00-161","supplier":"Henkel Bergquist / Digi-Key","unit_cost_usd":18,"qty":2},{"part_name":"Glycol Cooling Fluid (50/50 premix) 1L","part_number":"COOLANT-5050-1L","supplier":"Prestone / Grainger","unit_cost_usd":10,"qty":1}],"labor_minutes":60,"skill_level":"advanced","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"battery_cell_temp_delta_from_ambient_celsius","signal_source":"battery NTC array via BMS telemetry","threshold_value":12,"threshold_operator":">","threshold_unit":"celsius_delta","lead_time_hours":48,"confidence":0.7},{"signal_name":"cooling_pump_flow_rate_lpm","signal_source":"cooling circuit flow sensor","threshold_value":2.0,"threshold_operator":"<","threshold_unit":"liters_per_minute","lead_time_hours":72,"confidence":0.65}]},{"component":"dexterous hand actuators (Figure AI proprietary \u2014 16 DOF)","symptom":"finger position error exceeds \u00b12mm during grasp tasks, object drop rate increases, tendon/cable pops audibly during gripping cycle","root_cause":"tendon cable stretch and conduit wear in distal finger segments from repetitive pick-and-place with hard objects; pulley bearing micro-pitting in small-diameter (3-5mm) stainless bearings; tendon anchor crimp fatigue failure","severity":"high","mtbf_hours":1500,"source_urls":["unverified-training-data"],"confidence":"low","tags":["hand","actuator","tendon","humanoid","dexterity","cable"],"repair_protocol":{"title":"Hand Tendon Cable Inspection and Tension Calibration","steps":[{"step":1,"action":"Command hand to open/close calibration cycle 10 times via control software; record finger position error from encoder readings \u2014 identify fingers with error >1.5mm","tool":"robot control terminal","warning":null},{"step":2,"action":"Engage hand lockout; open hand dorsal access panel (snap-fit cover, plastic pry tool); expose tendon routing and pulley assembly","tool":"plastic pry tool, ESD wrist strap","warning":"Small bearings and springs \u2014 work over clean white surface to catch dropped components"},{"step":3,"action":"For each affected finger: pull tendon gently and feel for slack >0.5mm; inspect cable sheath for fraying under magnification; check anchor crimp for any wire escape","tool":"calipers, 10x loupe","warning":null},{"step":4,"action":"If tendon slack >1mm: adjust tension at motor-side tensioner (typically small M1.6 adjuster bolt) until slack is <0.3mm under 2N pull force","tool":"M1.6 hex driver, force gauge","warning":"Over-tensioning tears finger tendons \u2014 apply maximum 2N at finger tip"},{"step":5,"action":"Replace any cable showing >3 broken strands or anchor crimp damage; route new cable per manufacturer routing diagram; crimp new anchor with ratchet crimper to 50N pull-out force","tool":"ratchet crimper, replacement cable, routing diagram","warning":"Cable routing errors can jam finger mechanism \u2014 follow diagram exactly"},{"step":6,"action":"Reassemble; run finger calibration routine; confirm all fingers within \u00b11mm position error over 20-cycle test","tool":"robot calibration software","warning":null}],"tools_required":["robot control terminal","plastic pry tool","ESD wrist strap","calipers","10x loupe","M1.6 hex driver","force gauge","ratchet crimper"],"parts":[{"part_name":"Stainless Steel Aircraft Cable 0.8mm 7x7 (1m)","part_number":"T304-0.8MM-1M","supplier":"McMaster-Carr","unit_cost_usd":8,"qty":1},{"part_name":"Micro Stainless Bearing ABEC-7 3x8x3mm (10-pack)","part_number":"MR83ZZ-10PK","supplier":"NSK Ltd / Boca Bearing Company","unit_cost_usd":22,"qty":1}],"labor_minutes":120,"skill_level":"specialist","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"finger_position_error_mm_rms","signal_source":"finger encoder vs commanded position","threshold_value":1.5,"threshold_operator":">","threshold_unit":"mm","lead_time_hours":48,"confidence":0.67},{"signal_name":"grasp_object_drop_rate_pct","signal_source":"vision-based task success monitor","threshold_value":5,"threshold_operator":">","threshold_unit":"percent","lead_time_hours":24,"confidence":0.73}]},{"component":"firmware / VLA model synchronization","symptom":"robot executes correct high-level task command but physical motion is jerky or mis-timed, model inference latency spikes >200ms, robot requests human clarification for tasks it previously completed autonomously","root_cause":"VLA model version mismatch between edge compute and cloud after OTA partial update; real-time controller firmware clock synchronization drift from IEEE 1588 PTP network issue; model quantization artifacts at runtime causing action prediction error","severity":"medium","mtbf_hours":720,"source_urls":["unverified-training-data"],"confidence":"low","tags":["software","firmware","VLA","AI","humanoid","latency","OTA"],"repair_protocol":{"title":"Firmware Version Verification and VLA Model Redeployment","steps":[{"step":1,"action":"From fleet management console: check firmware version on all robot compute modules vs current release manifest; identify any module running non-current version","tool":"fleet management console","warning":null},{"step":2,"action":"Check PTP synchronization status: `ptp4l -f /etc/ptp4l.conf --slave_only 2>&1 | grep offset` \u2014 offset must be <50 microseconds; if >500\u03bcs, restart PTP service","tool":"SSH terminal","warning":null},{"step":3,"action":"If VLA model mismatch: force full model re-sync: `vla_deploy --full-sync --verify`; confirm model hash matches fleet manifest before allowing autonomous operation","tool":"SSH terminal / fleet console OTA tool","warning":"Do not allow robot to operate autonomously with unverified VLA model \u2014 task execution may be unpredictable"},{"step":4,"action":"After model sync: run 10-task qualification test suite (pick, place, navigate, handoff); confirm task success rate >95% and motion profile latency <150ms","tool":"robot task qualification suite","warning":null},{"step":5,"action":"If motion jerkiness persists post-sync: reboot all real-time control modules in sequence (joint controllers \u2192 state estimator \u2192 planner); confirm boot sequence completes without fault codes","tool":"fleet console module reboot tool","warning":null}],"tools_required":["fleet management console","SSH terminal"],"parts":[],"labor_minutes":45,"skill_level":"advanced","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"vla_inference_latency_ms_p99","signal_source":"inference engine performance monitor","threshold_value":180,"threshold_operator":">","threshold_unit":"milliseconds","lead_time_hours":4,"confidence":0.71},{"signal_name":"ptp_clock_offset_us","signal_source":"PTP synchronization daemon","threshold_value":200,"threshold_operator":">","threshold_unit":"microseconds","lead_time_hours":2,"confidence":0.76}]},{"component":"ankle and foot contact sensors","symptom":"robot unable to detect ground contact reliably during foot-strike, stumbles on transitions between surface types, gait controller reports 'contact uncertainty' warnings","root_cause":"foot force/torque sensor overload from hard foot-strikes on concrete exceeding sensor rated load (common in early-learning gait policies); cable damage to sensor signal wiring from flex fatigue at ankle pivot; sensor zero-offset drift from temperature","severity":"high","mtbf_hours":2500,"source_urls":["unverified-training-data"],"confidence":"low","tags":["sensor","foot","force-torque","humanoid","gait","contact"],"repair_protocol":{"title":"Foot Force-Torque Sensor Zero Calibration and Cable Inspection","steps":[{"step":1,"action":"Command robot to stand on flat surface, feet fully loaded; run force sensor zero calibration from software \u2014 sets current load as zero reference (tare)","tool":"robot calibration software","warning":"Robot must be stationary and stable during tare \u2014 any motion will corrupt calibration"},{"step":2,"action":"Run sensor linearity check: apply known weights (5kg, 10kg, 15kg test masses) to foot pad; verify sensor output within \u00b13% of expected value","tool":"calibrated test masses, robot diagnostic dashboard","warning":null},{"step":3,"action":"If sensor overrange alarm has triggered: inspect sensor housing for mechanical damage; check for zero offset >5% of full-scale after tare \u2014 indicates overload damage requiring sensor replacement","tool":"robot diagnostic software","warning":null},{"step":4,"action":"Inspect ankle flex cable: bend cable through full ankle range while monitoring resistance continuity on each wire \u2014 any intermittent (>\u00b15% change) = replace cable loom","tool":"multimeter, flex cable loom replacement","warning":null},{"step":5,"action":"After service: run gait validation on 10m test course with 5cm step transitions; confirm no 'contact uncertainty' warnings in 3 consecutive runs","tool":"test course, robot telemetry monitor","warning":null}],"tools_required":["robot calibration software","calibrated test masses 5/10/15kg","multimeter","robot diagnostic dashboard"],"parts":[{"part_name":"6-Axis Force/Torque Sensor (generic humanoid ankle size ~50Nm range)","part_number":"ATI-MINI45-E","supplier":"ATI Industrial Automation","unit_cost_usd":3500,"qty":1},{"part_name":"Custom Ankle Flex Cable Loom (OEM)","part_number":"FIG02-ANKLE-CABLE","supplier":"Figure AI Service","unit_cost_usd":280,"qty":1}],"labor_minutes":90,"skill_level":"specialist","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"foot_sensor_zero_offset_pct_fullscale","signal_source":"F/T sensor diagnostic","threshold_value":4,"threshold_operator":">","threshold_unit":"percent_of_full_scale","lead_time_hours":48,"confidence":0.64},{"signal_name":"contact_uncertainty_count_per_100_steps","signal_source":"gait controller event log","threshold_value":5,"threshold_operator":">","threshold_unit":"count_per_100_steps","lead_time_hours":12,"confidence":0.69}]}],"suppliers":[{"name":"Harmonic Drive LLC","website":"https://www.harmonicdrive.net","region":"NA","component_types":["harmonic drive","strain wave gear"],"lead_time_days":45,"risk_level":"high"},{"name":"ATI Industrial Automation","website":"https://www.ati-ia.com","region":"NA","component_types":["force-torque sensor","tool changer"],"lead_time_days":30,"risk_level":"medium"},{"name":"Henkel Bergquist","website":"https://www.henkel-adhesives.com","region":"NA","component_types":["thermal interface material"],"lead_time_days":7,"risk_level":"low"},{"name":"NSK Americas","website":"https://www.nskamericas.com","region":"NA","component_types":["micro bearing","precision bearing"],"lead_time_days":14,"risk_level":"medium"},{"name":"Figure AI Service","website":"https://www.figure.ai","region":"NA","component_types":["actuator module","cable loom","hand assembly"],"lead_time_days":21,"risk_level":"high"}],"research_sources":["unverified-training-data"]},{"slug":"tesla-optimus","name":"Tesla Optimus Gen2","manufacturer":"Tesla","type":"humanoid","introduced_year":2024,"specs_json":{"weight_kg":57,"dof":40,"height_m":1.73,"walking_speed_ms":1.0,"hand_dof":22,"battery_wh":2300,"compute":"Tesla FSD SoC","actuators":"proprietary linear + rotary"},"notes":"Tesla in-house manufacturing humanoid. Minimal external technical documentation. Failure modes based on engineering principles and publicly observable hardware. Confidence: low. FCC filings and teardown speculation are primary sources.","failure_modes":[{"component":"proprietary linear actuator (leg push-rod / knee extension)","symptom":"joint stiffness increase, linear actuator audible buzz at near-max extension, gait deviation detected by Tesla's internal vision-based gait monitor, joint position error >1cm","root_cause":"ball-screw drive nut preload loss from thermal cycling causing backlash increase; recirculating ball bearing wear from grit contamination in partially-sealed IP environment; motor winding insulation thermal degradation from high duty cycle in manufacturing environment (sustained walking)","severity":"critical","mtbf_hours":4000,"source_urls":["unverified-training-data"],"confidence":"low","tags":["actuator","ball-screw","humanoid","leg","linear-actuator","critical"],"repair_protocol":{"title":"Linear Actuator Backlash Check and Ball-Screw Inspection","steps":[{"step":1,"action":"Command Optimus to maintenance pose (supine, all joints centered); engage full E-stop via Tesla Optimus control tablet; verify all joint brakes engaged","tool":"Tesla control tablet","warning":"Tesla actuators contain high-tension springs \u2014 do not manually manipulate limbs without confirmed brake engagement"},{"step":2,"action":"Measure linear actuator backlash: attach dial indicator to output rod end; apply \u00b120N axial hand load; record total indicator movement \u2014 must be <0.2mm","tool":"dial indicator, rod-end attachment fixture","warning":null},{"step":3,"action":"If backlash >0.3mm: remove actuator module (connector-first, then structural bolts \u2014 typically 4x M6); open actuator housing to expose ball-screw nut","tool":"M6 hex key, actuator housing tool","warning":"Module is under-documented externally \u2014 photograph all wiring before disconnection"},{"step":4,"action":"Inspect ball-screw balls and nut races under magnification: replace full ball-screw assembly if any pitting visible; clean housing of metal debris","tool":"10x loupe, magnetic pick-up tool","warning":null},{"step":5,"action":"Repack ball-screw nut with Mobil Mobilux EP2 grease (5-8g); reassemble; verify backlash <0.15mm before reinstallation","tool":"grease syringe, dial indicator, Mobilux EP2","warning":null},{"step":6,"action":"Reinstall actuator; run joint calibration from Tesla software; confirm position tracking error <0.5mm over 10 full-range motion cycles","tool":"Tesla control software","warning":null}],"tools_required":["Tesla control tablet","dial indicator","M6 hex key","10x loupe","grease syringe","magnetic pick-up tool"],"parts":[{"part_name":"Thomson BSA12-3.175x3 Ball Screw Assembly (nearest commercial equivalent)","part_number":"TBSA12-3175X3","supplier":"Thomson Industries / Digi-Key","unit_cost_usd":280,"qty":1},{"part_name":"Mobil Mobilux EP2 Lithium Complex Grease 1kg","part_number":"102817","supplier":"ExxonMobil / Grainger","unit_cost_usd":32,"qty":1}],"labor_minutes":150,"skill_level":"specialist","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"linear_actuator_backlash_mm","signal_source":"actuator encoder round-trip position test","threshold_value":0.2,"threshold_operator":">","threshold_unit":"mm","lead_time_hours":168,"confidence":0.57},{"signal_name":"actuator_motor_current_rms_pct_baseline","signal_source":"actuator motor controller","threshold_value":122,"threshold_operator":">","threshold_unit":"percent","lead_time_hours":48,"confidence":0.63}]},{"component":"22-DOF hand (high-dexterity proprietary tendon-driven hand)","symptom":"finger grip force inconsistency >20% cycle-to-cycle, tendon pops audible during rapid close gesture, finger tip position wobbles during precision tasks","root_cause":"tendon cable micro-fatigue at sheave radius for small-bend (<8mm) pulleys common in 22-DOF hand architecture; actuator tendon pre-tensioner spring setpoint drift causing inconsistent tendon baseline tension; contact pad surface wear reducing tactile signal quality","severity":"high","mtbf_hours":2000,"source_urls":["unverified-training-data"],"confidence":"low","tags":["hand","tendon","actuator","humanoid","dexterity","cable"],"repair_protocol":{"title":"Hand Tendon Pre-Tension Inspection and Cable Integrity Check","steps":[{"step":1,"action":"Run hand self-test cycle from Tesla control software: 20 open/close cycles at 50% speed; log finger position deviation; identify fingers with >3mm tip deviation","tool":"Tesla control software","warning":null},{"step":2,"action":"Engage hand lockout; open dorsal access cover (proprietary tool or Torx T6 if accessible); expose tendon routing and pulley tree","tool":"Tesla hand service tool or Torx T6","warning":"Hand contains small ABEC-7 bearings and springs \u2014 work on anti-static mat over white paper"},{"step":3,"action":"For each problematic finger: pull tendon at proximal segment with 1N force; measure slack \u2014 acceptable <0.5mm; if >1mm, adjust at pre-tensioner","tool":"force gauge, calipers","warning":null},{"step":4,"action":"Inspect each tendon under 10x loupe at pulley contact point: any fraying, kinking, or >2 broken strands = replace cable segment","tool":"10x loupe","warning":null},{"step":5,"action":"Replace any failed tendon segment with 0.5mm 7x7 stainless aircraft cable; route per hand assembly diagram; crimp end with ratchet crimper; verify 30N pull-out from crimp","tool":"0.5mm 7x7 cable, ratchet crimper, assembly diagram","warning":null},{"step":6,"action":"Reassemble; run 50-cycle qualification at full speed; confirm tip deviation <1.5mm and grip force consistency >90%","tool":"Tesla control software, grip force test object","warning":null}],"tools_required":["Tesla control software","Tesla hand service tool or Torx T6","force gauge","calipers","10x loupe","ratchet crimper","anti-static mat"],"parts":[{"part_name":"Stainless Aircraft Cable 0.5mm 7x7 (2m)","part_number":"T304-0.5MM-2M","supplier":"McMaster-Carr","unit_cost_usd":10,"qty":1},{"part_name":"Micro Swage Crimp Ferrule 0.5mm Stainless (50-pack)","part_number":"CRIMP-05-SS-50","supplier":"McMaster-Carr","unit_cost_usd":12,"qty":1}],"labor_minutes":120,"skill_level":"specialist","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"hand_finger_tip_deviation_mm_p95","signal_source":"hand encoder array","threshold_value":2.5,"threshold_operator":">","threshold_unit":"mm","lead_time_hours":48,"confidence":0.6},{"signal_name":"grip_force_cycle_variance_pct","signal_source":"grip force sensor / actuator torque proxy","threshold_value":20,"threshold_operator":">","threshold_unit":"percent","lead_time_hours":24,"confidence":0.64}]},{"component":"Tesla FSD SoC compute platform (onboard inference)","symptom":"increased task latency, motion planning solution not found within 500ms timeout, SoC thermal throttle warning in logs, robot enters conservative 'reduced capability' mode","root_cause":"FSD SoC operating at 90%+ CPU/NPU utilization from perception pipeline workload in cluttered manufacturing environment; thermal throttle from cooling system dust accumulation on heat sink fins; NPU SRAM soft errors from cosmic ray single-event upsets (rare but documented in ARM cores)","severity":"high","mtbf_hours":5000,"source_urls":["unverified-training-data"],"confidence":"low","tags":["compute","SoC","thermal","firmware","humanoid","AI-inference"],"repair_protocol":{"title":"FSD SoC Thermal Cleaning and Utilization Optimization","steps":[{"step":1,"action":"Pull SoC performance telemetry: CPU utilization, NPU utilization, thermal zone temperatures, throttle events per hour over past 7 days","tool":"Tesla fleet diagnostic console","warning":null},{"step":2,"action":"Access compute module cooling air inlet (location per Tesla service guide \u2014 typically rear torso); use compressed air at 30 PSI to clear dust from heat sink fins; measure airflow improvement","tool":"compressed air can 30 PSI, airflow indicator strip","warning":"ESD precaution \u2014 ground yourself before accessing compute compartment"},{"step":3,"action":"Check thermal interface between SoC and heat sink: if SoC package temp >85\u00b0C at 50% NPU load, replace thermal interface material; apply Shin-Etsu X-23 paste 0.1mm layer","tool":"Shin-Etsu X-23 thermal paste, plastic spatula, isopropyl alcohol","warning":null},{"step":4,"action":"If NPU SRAM errors in logs (ECC error count >0 per week): perform memory ECC scrub via Tesla diagnostic tool; if persistent, SoC replacement required (factory service)","tool":"Tesla diagnostic tool","warning":null},{"step":5,"action":"Optimize perception pipeline configuration: reduce camera resolution for non-safety-critical views from 1080p to 720p in stable-lighting environments; confirm NPU utilization drops to <75%","tool":"Tesla configuration console","warning":"Do not reduce resolution on safety-critical forward-facing cameras without engineering sign-off"}],"tools_required":["Tesla fleet diagnostic console","compressed air 30 PSI","Shin-Etsu X-23 thermal paste","plastic spatula","isopropyl alcohol"],"parts":[{"part_name":"Shin-Etsu X-23-7762 Thermal Paste 7g","part_number":"X-23-7762-7G","supplier":"Shin-Etsu Chemical / Digi-Key","unit_cost_usd":15,"qty":1}],"labor_minutes":50,"skill_level":"advanced","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"fsd_soc_temperature_celsius","signal_source":"SoC thermal zone sensor","threshold_value":82,"threshold_operator":">","threshold_unit":"celsius","lead_time_hours":4,"confidence":0.72},{"signal_name":"npu_utilization_pct_1h_avg","signal_source":"SoC performance counters","threshold_value":88,"threshold_operator":">","threshold_unit":"percent","lead_time_hours":12,"confidence":0.68}]},{"component":"rotary actuator (shoulder / hip \u2014 BLDC + cycloidal or planetary gearbox)","symptom":"joint torque output drops to 60% of commanded, robot shifts to low-torque mode for affected limb, gear noise at low speed, joint vibration during slow controlled motion","root_cause":"cycloidal gearbox pin roller bearing fatigue from high-cycle manufacturing use; planetary carrier bearing wear from sustained radial loads; motor encoder magnetic interference from adjacent actuators causing commutation errors","severity":"critical","mtbf_hours":3500,"source_urls":["unverified-training-data"],"confidence":"low","tags":["actuator","gearbox","humanoid","shoulder","hip","BLDC","critical"],"repair_protocol":{"title":"Rotary Actuator Gearbox Inspection and Bearing Service","steps":[{"step":1,"action":"Pull actuator efficiency telemetry: compare motor input power vs output torque \u00d7 speed; efficiency <75% indicates gearbox loss; cross-check with gear noise audio analysis if equipped","tool":"Tesla diagnostic console","warning":null},{"step":2,"action":"Command robot to maintenance pose; lockout; remove actuator module: disconnect motor connector and encoder cable; remove 4-6x M6 structural bolts; extract module","tool":"M6 hex key, connector extraction tool, torque wrench","warning":null},{"step":3,"action":"On bench: measure gear stage backlash \u2014 apply \u00b110 Nm to output; measure input shaft rotation (should be <0.05\u00b0 for cycloidal, <0.1\u00b0 for planetary)","tool":"precision rotation sensor, torque wrench","warning":null},{"step":4,"action":"Open gearbox (proprietary fasteners expected): inspect pin rollers and ring gear; any pitting >0.1mm on pin rollers = replace cycloidal stage; record all gear measurements","tool":"proprietary gearbox tool, 10x loupe, calipers","warning":null},{"step":5,"action":"Replace carrier bearings with matched precision set (ABEC-5 or better); repack with Kl\u00fcber Isoflex NBU 15 ultra-precision bearing grease; reassemble gearbox to 0.02mm backlash spec","tool":"ABEC-5 bearing set, precision assembly fixtures, Kl\u00fcber Isoflex NBU 15 grease","warning":"Cycloidal gearbox reassembly requires precision tooling \u2014 factory service only for full disassembly"},{"step":6,"action":"Reinstall actuator module; run efficiency test; confirm >85% mechanical efficiency; run position accuracy test <0.2\u00b0 error at max rated torque","tool":"Tesla diagnostic software","warning":null}],"tools_required":["Tesla diagnostic console","M6 hex key","precision rotation sensor","torque wrench","10x loupe","calipers","ABEC-5 precision bearing set"],"parts":[{"part_name":"Kl\u00fcber Isoflex NBU 15 Ultra-Precision Bearing Grease 50g","part_number":"099120-082","supplier":"Kl\u00fcber Lubrication / Grainger","unit_cost_usd":65,"qty":1},{"part_name":"ABEC-5 Precision Bearing Set (cycloidal carrier \u2014 OEM match)","part_number":"TSLA-OPT-BEAR-SET-HIP","supplier":"Tesla Service Parts","unit_cost_usd":380,"qty":1}],"labor_minutes":200,"skill_level":"specialist","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"actuator_mechanical_efficiency_pct","signal_source":"motor power in vs joint torque \u00d7 speed out","threshold_value":78,"threshold_operator":"<","threshold_unit":"percent","lead_time_hours":72,"confidence":0.66},{"signal_name":"gearbox_vibration_rms_g_at_joint","signal_source":"accelerometer on actuator housing","threshold_value":0.5,"threshold_operator":">","threshold_unit":"g","lead_time_hours":48,"confidence":0.62}]},{"component":"battery pack thermal management (2300Wh, liquid-cooled)","symptom":"runtime reduced from 8h target to 5h, battery max charge voltage reduced by BMS to 90% capacity, coolant pump warning LED, pack surface temperature uneven","root_cause":"liquid coolant micro-channel blockage from mineral precipitation in non-deionized coolant; cooling pump brushless motor bearing wear reducing flow rate; cell chemistry (assumed NMC 811 or LFP based on Tesla supply chain) sensitivity to >38\u00b0C cell temperature during fast charge","severity":"high","mtbf_hours":5000,"source_urls":["unverified-training-data"],"confidence":"low","tags":["battery","thermal","cooling","humanoid","BMS","liquid-cooling"],"repair_protocol":{"title":"Battery Cooling Pump Inspection and Coolant Flush","steps":[{"step":1,"action":"Pull cooling system telemetry: inlet vs outlet temperature differential (\u0394T); must be 5-8\u00b0C at nominal load; \u0394T >12\u00b0C indicates low flow; \u0394T <2\u00b0C indicates no flow or short-circuit","tool":"Tesla diagnostic console","warning":null},{"step":2,"action":"Access cooling system service port (Tesla Optimus \u2014 assumed similar to Tesla vehicle architecture \u2014 HVAC system on upper torso); attach cooling loop pressure gauge; measure flow rate indicator","tool":"cooling pressure gauge kit","warning":"48V battery system \u2014 lockout before accessing any cooling circuit near battery"},{"step":3,"action":"Drain cooling loop via drain plug; flush with 1L deionized water; refill with Tesla-spec coolant (assumed OAT extended-life ethylene glycol or Tesla Novec-equivalent); bleed air","tool":"drain container, deionized water, Tesla-spec coolant, bleed tool","warning":"Use only manufacturer-specified coolant \u2014 incorrect chemistry causes aluminum corrosion in micro-channels"},{"step":4,"action":"Check cooling pump: measure pump motor current at startup vs spec; if >20% over baseline or pump fails to start within 2 seconds, replace pump assembly","tool":"multimeter, pump spec datasheet","warning":null},{"step":5,"action":"After service: run full charge/discharge cycle; monitor cell temperature max \u2014 confirm <36\u00b0C throughout cycle in 22\u00b0C ambient","tool":"Tesla diagnostic console, ambient thermometer","warning":null}],"tools_required":["Tesla diagnostic console","cooling pressure gauge","drain container","deionized water supply","ambient thermometer"],"parts":[{"part_name":"Tesla OAT Extended-Life Coolant Concentrate 1L (diluted 50/50 with DI water)","part_number":"TSLA-COOLANT-OAT-1L","supplier":"Tesla Service Parts","unit_cost_usd":25,"qty":1},{"part_name":"Micro Cooling Pump DC 24V 5LPM (nearest commercial equivalent)","part_number":"D5-VARIO-LT12V-12V","supplier":"Laing Thermotech / McMaster-Carr","unit_cost_usd":85,"qty":1}],"labor_minutes":75,"skill_level":"advanced","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"cooling_delta_T_celsius","signal_source":"coolant inlet vs outlet thermistor","threshold_value":11,"threshold_operator":">","threshold_unit":"celsius","lead_time_hours":24,"confidence":0.67},{"signal_name":"battery_soh_pct","signal_source":"BMS state-of-health register","threshold_value":85,"threshold_operator":"<","threshold_unit":"percent","lead_time_hours":336,"confidence":0.75}]},{"component":"vision-based localization (FSD camera array \u2014 torso + head mounted)","symptom":"robot loses position in manufacturing cell after lighting change, returns incorrect object pose for grasping task, repeated task abort events linked to 'pose uncertainty too high'","root_cause":"FSD neural network localization degrading under factory lighting conditions not well-represented in training data (sodium vapor lamps, variable LED intensity); camera lens soiling from manufacturing environment particulates (metal chips, coolant mist); adversarial environment conditions causing distribution shift","severity":"high","mtbf_hours":1200,"source_urls":["unverified-training-data"],"confidence":"low","tags":["vision","localization","perception","camera","FSD","humanoid","manufacturing"],"repair_protocol":{"title":"Camera Lens Cleaning and Visual Localization Reference Map Update","steps":[{"step":1,"action":"Review task abort log for pattern: if aborts cluster around specific lighting state or time of day, flag for lighting environment remediation before camera service","tool":"Tesla fleet console abort log","warning":null},{"step":2,"action":"Clean all camera lenses: remove dust cover (if present); apply 2 sprays Zeiss Lens Care solution to microfibre cloth; wipe each lens with single radial strokes","tool":"Zeiss Lens Care spray, microfibre cloths","warning":"Do not spray solution directly on lens \u2014 spray on cloth first; avoid anti-reflective coating damage"},{"step":3,"action":"Update visual localization reference map for the manufacturing cell: run 'map capture' mode \u2014 robot walks slowly around cell perimeter at 0.3 m/s; system captures new lighting-corrected visual fingerprint map","tool":"Tesla control software map-capture mode","warning":null},{"step":4,"action":"Test localization: drive robot to 10 known waypoints; measure position error with external tracker (laser tracker or AprilTag ground truth); max error 15mm in XY, 2\u00b0 in yaw","tool":"laser tracker or AprilTag ground truth fixture, measuring tape","warning":null},{"step":5,"action":"If localization error persists: install supplementary structured light markers (retroreflective targets) at 2m height around cell; update localization to use marker-fusion mode","tool":"retroreflective markers, drill, measuring tape","warning":null}],"tools_required":["Tesla fleet console","Zeiss Lens Care spray","microfibre cloths","laser tracker or AprilTag ground truth"],"parts":[{"part_name":"Zeiss Lens Care Plus Spray 240ml","part_number":"000000-2096-075","supplier":"Carl Zeiss Vision","unit_cost_usd":14,"qty":1},{"part_name":"Retroreflective Survey Target 75mm dia (10-pack)","part_number":"RR-75-10PK","supplier":"Prism Survey Supply / Amazon","unit_cost_usd":22,"qty":1}],"labor_minutes":75,"skill_level":"advanced","source_url":"unverified-training-data"},"predictive_signals":[{"signal_name":"task_abort_rate_per_shift","signal_source":"Tesla fleet task execution log","threshold_value":5,"threshold_operator":">","threshold_unit":"count_per_shift","lead_time_hours":8,"confidence":0.7},{"signal_name":"pose_uncertainty_covariance_trace_m2","signal_source":"visual localization module","threshold_value":0.01,"threshold_operator":">","threshold_unit":"m_squared","lead_time_hours":2,"confidence":0.65}]}],"suppliers":[{"name":"Thomson Industries","website":"https://www.thomsonlinear.com","region":"NA","component_types":["ball screw","linear actuator","linear guide"],"lead_time_days":21,"risk_level":"medium"},{"name":"Kl\u00fcber Lubrication","website":"https://www.klueber.com","region":"global","component_types":["precision grease","thermal lubricant"],"lead_time_days":14,"risk_level":"low"},{"name":"NSK Americas","website":"https://www.nskamericas.com","region":"NA","component_types":["precision bearing","ABEC-5 bearing","ball screw nut"],"lead_time_days":14,"risk_level":"medium"},{"name":"Tesla Service Parts","website":"https://www.tesla.com","region":"NA","component_types":["actuator module","battery pack","compute module","coolant"],"lead_time_days":30,"risk_level":"high"},{"name":"Shin-Etsu Chemical America","website":"https://www.shinetsu.co.jp","region":"NA","component_types":["thermal interface paste","silicone compound"],"lead_time_days":7,"risk_level":"low"}],"research_sources":["unverified-training-data"]}]$jdata$::jsonb;
  p   jsonb;
  fm  jsonb;
  sig jsonb;
  pid  uuid;
  fmid uuid;
BEGIN
  FOR p IN SELECT value FROM jsonb_array_elements(d)
  LOOP
    SELECT id INTO pid FROM platforms WHERE slug = p->>'slug';
    IF pid IS NULL THEN
      INSERT INTO platforms (slug,name,manufacturer,type,introduced_year,specs_json,techmedix_status)
      VALUES (p->>'slug',p->>'name',p->>'manufacturer',p->>'type',
              NULLIF(p->>'introduced_year','null')::integer,
              COALESCE(p->'specs_json','{}'::jsonb),'supported')
      RETURNING id INTO pid;
    END IF;
    FOR fm IN SELECT value FROM jsonb_array_elements(p->'failure_modes')
    LOOP
      INSERT INTO failure_modes (platform_id,component,symptom,root_cause,severity,mtbf_hours,source_urls,confidence,tags)
      VALUES (pid, fm->>'component', fm->>'symptom', fm->>'root_cause',
              COALESCE(fm->>'severity','medium'),
              NULLIF(fm->>'mtbf_hours','null')::integer,
              ARRAY(SELECT jsonb_array_elements_text(COALESCE(fm->'source_urls','["unverified-training-data"]'::jsonb))),
              COALESCE(fm->>'confidence','low'),
              ARRAY(SELECT jsonb_array_elements_text(COALESCE(fm->'tags','[]'::jsonb))))
      ON CONFLICT (platform_id,component,symptom) DO UPDATE SET severity=EXCLUDED.severity, updated_at=now()
      RETURNING id INTO fmid;
      IF fm ? 'repair_protocol' THEN
        INSERT INTO repair_protocols (failure_mode_id,title,steps_json,tools_required,parts_json,labor_minutes,skill_level,source_url,verified_by,version)
        SELECT fmid,
               fm->'repair_protocol'->>'title',
               COALESCE(fm->'repair_protocol'->'steps','[]'::jsonb),
               ARRAY(SELECT jsonb_array_elements_text(COALESCE(fm->'repair_protocol'->'tools_required','[]'::jsonb))),
               COALESCE(fm->'repair_protocol'->'parts','[]'::jsonb),
               NULLIF(fm->'repair_protocol'->>'labor_minutes','null')::integer,
               COALESCE(fm->'repair_protocol'->>'skill_level','intermediate'),
               fm->'repair_protocol'->>'source_url',
               'research_agent', 1
        WHERE NOT EXISTS (SELECT 1 FROM repair_protocols WHERE failure_mode_id=fmid);
      END IF;
      FOR sig IN SELECT value FROM jsonb_array_elements(COALESCE(fm->'predictive_signals','[]'::jsonb))
      LOOP
        INSERT INTO predictive_signals (failure_mode_id,signal_name,signal_source,threshold_value,threshold_operator,threshold_unit,lead_time_hours,confidence,notes)
        SELECT fmid, sig->>'signal_name', sig->>'signal_source',
               NULLIF(sig->>'threshold_value','null')::numeric,
               COALESCE(sig->>'threshold_operator','>'),
               sig->>'threshold_unit',
               NULLIF(sig->>'lead_time_hours','null')::integer,
               NULLIF(sig->>'confidence','null')::numeric,
               sig->>'notes'
        WHERE NOT EXISTS (SELECT 1 FROM predictive_signals WHERE failure_mode_id=fmid AND signal_name=sig->>'signal_name');
      END LOOP;
    END LOOP;
  END LOOP;
END $$;